func TestEnumEmployeeStatus(t *testing.T) {
	t.Run("NewFromString_ACTIVE", func(t *testing.T) {
		t.Parallel()
		val, err := NewEmployeeStatusFromString("ACTIVE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EmployeeStatus("ACTIVE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_INACTIVE", func(t *testing.T) {
		t.Parallel()
		val, err := NewEmployeeStatusFromString("INACTIVE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EmployeeStatus("INACTIVE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewEmployeeStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewEmployeeStatusFromString("ACTIVE")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesEmployee(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &Employee{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *Employee
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

